mapper.delete:
delete from room_rsvn_member 
where rsvn_seq in

	#{rsvn_seq}

mapper.select:
select r.*, u.name
from room_rsvn r
JOIN users u ON u.id = r.users_id
where r.room_seq = #{room_seq}
and TO_CHAR(r.start_dt, 'YYYY-MM-DD') = #{date}

select 
	TO_CHAR(start_dt, 'HH24:MI') as startTime,
	TO_CHAR(end_dt, 'HH24:MI') as endTime
from room_rsvn where room_seq = #{room_seq}
	and TRUNC(start_dt) = TO_DATE(#{date}, 'YYYY-MM-DD')
	and rsvn_seq != #{rsvn_seq}
